539	func ensureLandingWorktreeReady(dir, targetBranch string) error {
540		if !isInsideGitWorktree(dir) {
541			return nil
542		}
543		branchOut, err := internalgit.Command(context.Background(), dir, "branch", "--show-current").CombinedOutput()
544		if err != nil {
545			return fmt.Errorf("checking landing branch: %s: %w", strings.TrimSpace(string(branchOut)), err)
546		}
547		branch := strings.TrimSpace(string(branchOut))
548		if branch == "" {
549			return fmt.Errorf("landing worktree is detached; expected branch %q", targetBranch)
550		}
551		if targetBranch != "" && branch != targetBranch {
552			return fmt.Errorf("landing branch mismatch: on %q, want %q", branch, targetBranch)
553		}
554		return waitForEmptyGitIndex(dir, 2*time.Second)
555	}
