557	func isInsideGitWorktree(dir string) bool {
558		out, err := internalgit.Command(context.Background(), dir, "rev-parse", "--is-inside-work-tree").CombinedOutput()
559		return err == nil && strings.TrimSpace(string(out)) == "true"
560	}
