634	func (RealLandingGitOps) AddWorktree(dir, path, rev string) error {
635		// --detach so the worktree does not create a persistent branch.
636		out, err := internalgit.Command(context.Background(), dir, "worktree", "add", "--force", "--detach", path, rev).CombinedOutput()
637		if err != nil {
638			return fmt.Errorf("git worktree add %s %s: %s: %w", path, rev, strings.TrimSpace(string(out)), err)
639		}
640		return nil
641	}
