725	func (RealLandingGitOps) CommitStaged(dir, msg string) (string, error) {
726		out, _ := internalgit.Command(context.Background(), dir, "diff", "--cached", "--name-only").Output()
727		if len(strings.TrimSpace(string(out))) == 0 {
728			return "", nil
729		}
730		commitOut, err := internalgit.Command(context.Background(), dir,
731			"-c", "user.name=ddx-land-coordinator",
732			"-c", "user.email=coordinator@ddx.local",
733			"commit", "-m", msg,
734		).CombinedOutput()
735		if err != nil {
736			return "", fmt.Errorf("git commit: %s: %w", strings.TrimSpace(string(commitOut)), err)
737		}
738		shaOut, err := internalgit.Command(context.Background(), dir, "rev-parse", "HEAD").Output()
739		if err != nil {
740			return "", fmt.Errorf("rev-parse HEAD after evidence commit: %w", err)
741		}
742		return strings.TrimSpace(string(shaOut)), nil
743	}
