769	// FetchOriginAncestryCheck implements LandingGitOps.FetchOriginAncestryCheck.
770	func (RealLandingGitOps) FetchOriginAncestryCheck(dir, targetBranch string) (PreClaimResult, error) {
771		var result PreClaimResult
772		err := withMainGitLock(dir, func() error {
773			var checkErr error
774			result, checkErr = fetchOriginAncestryCheckLocked(dir, targetBranch)
775			return checkErr
776		})
777		return result, err
778	}
779	
780	func fetchOriginAncestryCheckLocked(dir, targetBranch string) (PreClaimResult, error) {
781		if err := ensureLandingWorktreeReady(dir, targetBranch); err != nil {
782			return PreClaimResult{}, err
783		}
784	
785		// Step 1: check for origin remote.
786		out, err := internalgit.Command(context.Background(), dir, "remote", "get-url", "origin").CombinedOutput()
787		if err != nil {
788			// No origin remote — single-machine case; skip check.
789			return PreClaimResult{Action: "no-origin"}, nil
790		}
791		_ = out // remote URL not needed
792	
793		// Step 2: fetch origin/targetBranch (best-effort; failure is non-fatal but surfaced).
794		if fetchOut, fetchErr := internalgit.Command(context.Background(), dir, "fetch", "origin", targetBranch).CombinedOutput(); fetchErr != nil {
795			return PreClaimResult{}, &fetchOriginError{
796				targetBranch: targetBranch,
797				output:       strings.TrimSpace(string(fetchOut)),
798				err:          fetchErr,
799			}

800		}
801	
802		// Step 3: resolve local tip.
803		localOut, localErr := internalgit.Command(context.Background(), dir, "rev-parse", "--verify", "refs/heads/"+targetBranch).CombinedOutput()
804		if localErr != nil {
805			return PreClaimResult{}, fmt.Errorf("resolving local %s: %s: %w", targetBranch, strings.TrimSpace(string(localOut)), localErr)
806		}
807		localSHA := strings.TrimSpace(string(localOut))
808	
809		// Step 4: resolve origin tip.
810		originOut, originErr := internalgit.Command(context.Background(), dir, "rev-parse", "--verify", "refs/remotes/origin/"+targetBranch).CombinedOutput()
811		if originErr != nil {
812			return PreClaimResult{}, fmt.Errorf("resolving origin/%s: %s: %w", targetBranch, strings.TrimSpace(string(originOut)), originErr)
813		}
814		originSHA := strings.TrimSpace(string(originOut))
815	
816		// Step 5: compare.
817		if localSHA == originSHA {
818			return PreClaimResult{Action: "unchanged", LocalSHA: localSHA, OriginSHA: originSHA}, nil
819		}
820	
821		// Is local an ancestor of origin? (origin is ahead)
822		localAncestorErr := internalgit.Command(context.Background(), dir, "merge-base", "--is-ancestor", localSHA, originSHA).Run()
823		if localAncestorErr == nil {
824			// Origin is ahead: fast-forward local branch via update-ref + sync worktree.
825			targetRef := "refs/heads/" + targetBranch
826			if upErr := internalgit.Command(context.Background(), dir, "update-ref", targetRef, originSHA, localSHA).Run(); upErr != nil {
827				return PreClaimResult{}, fmt.Errorf("fast-forwarding %s to %s: %w", targetRef, originSHA, upErr)
828			}
829			// Sync index + working tree to new HEAD so the main worktree files
830			// reflect the pulled-down origin commits. Pass localSHA as fromRev
831			// to restrict the restore to files actually changed by origin's
832			// advance, preserving unrelated local modifications.
833			_ = (RealLandingGitOps{}).SyncWorkTreeToHead(dir, localSHA)
834			return PreClaimResult{Action: "fast-forwarded", LocalSHA: localSHA, OriginSHA: originSHA}, nil
835		}
836	
837		// Is origin an ancestor of local? (local is ahead)
838		originAncestorErr := internalgit.Command(context.Background(), dir, "merge-base", "--is-ancestor", originSHA, localSHA).Run()
839		if originAncestorErr == nil {
840			return PreClaimResult{Action: "local-ahead", LocalSHA: localSHA, OriginSHA: originSHA}, nil
841		}
842	
843		// Neither is ancestor of the other: diverged.
844		return PreClaimResult{Action: "diverged", LocalSHA: localSHA, OriginSHA: originSHA}, nil
845	}
