903	// evidenceDirHasTrackedFiles reports whether any files under dirRel are tracked
904	// in git at wd. Used by landEvidence to distinguish "nothing staged because
905	// already committed" from "nothing staged because evidence is absent."
906	func evidenceDirHasTrackedFiles(wd, dirRel string) bool {
907		out, err := internalgit.Command(context.Background(), wd, "ls-files", "--", filepath.FromSlash(dirRel)).Output()
908		return err == nil && len(strings.TrimSpace(string(out))) > 0
909	}
