1461	func svelteSanityFailure(base, result []byte) (string, bool) {
1462		baseHadScript := bytes.Contains(base, []byte("<script"))
1463		resultHasScript := bytes.Contains(result, []byte("<script"))
1464		resultClosesScript := bytes.Contains(result, []byte("</script>"))
