1515	// landPushAutoMergeConflictError tags a recovery error that originates from
1516	// an unresolvable git merge conflict, so landPush can branch on it without
1517	// pattern-matching free-form error strings.
1518	type landPushAutoMergeConflictError struct{ inner error }
1519	
1520	func (e *landPushAutoMergeConflictError) Error() string { return e.inner.Error() }
1521	func (e *landPushAutoMergeConflictError) Unwrap() error { return e.inner }
1522	
1523	func isPushAutoMergeConflict(err error) bool {
1524		for err != nil {
1525			if _, ok := err.(*landPushAutoMergeConflictError); ok {
1526				return true
1527			}
1528			type unwrapper interface{ Unwrap() error }
1529			u, ok := err.(unwrapper)
1530			if !ok {
1531				return false
1532			}
1533			err = u.Unwrap()
1534		}
1535		return false
1536	}
