1739	// BuildLandRequestFromResult constructs a LandRequest for the coordinator from
1740	// an ExecuteBeadResult. The coordinator always passes projectRoot as the
1741	// workdir — the worker's original worktree has already been cleaned up by the
1742	// time Land() runs.
1743	func BuildLandRequestFromResult(projectRoot string, res *ExecuteBeadResult) LandRequest {
1744		// Use the pre-landing implementation revision. If ImplementationRev is set
1745		// (i.e. the result was already landed once and ResultRev was rewritten to
1746		// the branch tip), prefer it so the coordinator always sees the candidate
1747		// commit rather than an already-landed or evidence rev.
1748		candidateRev := res.ImplementationRev
1749		if candidateRev == "" {
1750			candidateRev = res.ResultRev
1751		}
1752		return LandRequest{
1753			WorktreeDir:  projectRoot,
1754			BaseRev:      res.BaseRev,
1755			ResultRev:    candidateRev,
1756			BeadID:       res.BeadID,
1757			AttemptID:    res.AttemptID,
1758			TargetBranch: "",
1759			EvidenceDir:  res.ExecutionDir,
1760		}
