1090		}
1091		if got := r.resolveRef("refs/heads/main"); got != workerSHA {
1092			t.Errorf("local main tip = %s, want %s", got, workerSHA)
1093		}
1094		// Force-push canary: ensure no --force was used. The unreachable path
