// FetchOriginAncestryCheck fetches origin/targetBranch and compares it to the
// local branch tip. When origin is ahead the local branch is fast-forwarded
// via update-ref + read-tree. When the two tips have diverged the returned
// result has Action == "diverged". When no origin remote exists the result has
// Action == "no-origin". This method is NOT part of LandingGitOps — Land() is
// local-only. It is used by the pre-claim hook (see PreClaimGitOps).
// Network failures are surfaced as errors whose message begins with
// "git fetch origin"; callers can swallow those while propagating
// local worktree safety errors.
func (RealLandingGitOps) FetchOriginAncestryCheck(dir, targetBranch string) (PreClaimResult, error) {
	var result PreClaimResult
	err := withMainGitLock(dir, func() error {
		var checkErr error
		result, checkErr = fetchOriginAncestryCheckLocked(dir, targetBranch)
		return checkErr
	})
	return result, err
}

func fetchOriginAncestryCheckLocked(dir, targetBranch string) (PreClaimResult, error) {
	if err := ensureLandingWorktreeReady(dir, targetBranch); err != nil {
		return PreClaimResult{}, err
	}

	// Step 1: check for origin remote.
	out, err := internalgit.Command(context.Background(), dir, "remote", "get-url", "origin").CombinedOutput()
	if err != nil {
		// No origin remote — single-machine case; skip check.
		return PreClaimResult{Action: "no-origin"}, nil
	}
	_ = out // remote URL not needed

	// Step 2: fetch origin/targetBranch (best-effort; failure is non-fatal).
	if fetchOut, fetchErr := internalgit.Command(context.Background(), dir, "fetch", "origin", targetBranch).CombinedOutput(); fetchErr != nil {
		return PreClaimResult{}, fmt.Errorf("git fetch origin %s: %s: %w",
			targetBranch, strings.TrimSpace(string(fetchOut)), fetchErr)

