// localOnlyGitOps embeds RealLandingGitOps without any network methods.
// If LandingGitOps grows FetchBranch, PushFFOnly, or HasRemote this
// compile-time assertion will fail, catching the regression immediately.
type localOnlyGitOps struct{ RealLandingGitOps }

var _ LandingGitOps = localOnlyGitOps{}

// TestLand_IsNetworkFree is a compile-time + runtime guard that Land() and
// LandingGitOps remain free of network I/O (fetch/push). The compile-time
// assertion above enforces it structurally; the loop below catches any method
// added to the interface that carries a network-operation name.
func TestLand_IsNetworkFree(t *testing.T) {
	iface := reflect.TypeOf((*LandingGitOps)(nil)).Elem()
	for i := 0; i < iface.NumMethod(); i++ {
		name := iface.Method(i).Name
		for _, bad := range []string{"Fetch", "Push", "HasRemote"} {
			if strings.Contains(name, bad) {
				t.Errorf("LandingGitOps has network method %q — Land() must be local-only (no fetch, no push)", name)
			}
		}
	}
}

// TestLand_LockReleasedWithinOneSecond verifies that the main-git lock hold
// duration for a successful Land() call is under 1 second (AC #4). Network I/O
// (fetch/push) has been moved outside the lock; only local git ops remain.
func TestLand_LockReleasedWithinOneSecond(t *testing.T) {
	r := newLandTestRepo(t)
	ops := RealLandingGitOps{}

	workerSHA := r.commitOn(r.baseSHA, "feature.txt", "content\n", "feat: feature")

	req := LandRequest{
		WorktreeDir:  r.dir,
		BaseRev:      r.baseSHA,
		ResultRev:    workerSHA,
		BeadID:       "ddx-land-lockduration",
		AttemptID:    "20260510T000001-ld",
		TargetBranch: "main",
	}

	var holdDuration time.Duration
	prev := TrackerLockMetricsSink
	TrackerLockMetricsSink = func(s TrackerLockSample) {
		holdDuration = s.Hold
	}
	defer func() { TrackerLockMetricsSink = prev }()

	_, err := Land(r.dir, req, ops)
	if err != nil {
		t.Fatalf("Land: %v", err)
	}

	const limit = time.Second
	if holdDuration > limit {
		t.Errorf("withMainGitLock hold = %v, want <= %v (network I/O must be outside the lock)", holdDuration, limit)
	}
	if holdDuration == 0 {
		t.Error("TrackerLockMetricsSink was never called — verify the sink is wired to withMainGitLock")
	}
}

